export const DASHBOARD_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n<title>Localizit — BLE Tracker Platform (prototype)</title>\n<link rel=\"stylesheet\" href=\"https://unpkg.com/leaflet@1.9.4/dist/leaflet.css\" />\n<style>\n  :root { --bg:#0f1419; --panel:#1a2230; --line:#2a3548; --txt:#e6edf3; --mut:#8b98a9;\n          --accent:#3b82f6; --red:#ef4444; --amber:#f59e0b; --green:#22c55e; }\n  * { box-sizing:border-box; }\n  body { margin:0; font:15px/1.45 -apple-system,BlinkMacSystemFont,\"Segoe UI\",sans-serif;\n         background:var(--bg); color:var(--txt); display:flex; height:100vh; overflow:hidden; }\n  #side { width:380px; min-width:380px; background:var(--panel); border-right:1px solid var(--line);\n          display:flex; flex-direction:column; }\n  header { padding:16px; border-bottom:1px solid var(--line); }\n  header h1 { margin:0; font-size:18px; }\n  header p { margin:4px 0 0; color:var(--mut); font-size:12px; }\n  #map { flex:1; }\n  .section { padding:12px 16px; border-bottom:1px solid var(--line); }\n  .section h2 { margin:0 0 8px; font-size:12px; letter-spacing:.08em; text-transform:uppercase; color:var(--mut); }\n  .asset { padding:8px; border:1px solid var(--line); border-radius:8px; margin-bottom:8px; cursor:pointer; }\n  .asset.active { border-color:var(--accent); background:rgba(59,130,246,.08); }\n  .asset .row { display:flex; justify-content:space-between; align-items:center; }\n  .asset .name { font-weight:600; }\n  .asset .meta { color:var(--mut); font-size:12px; margin-top:2px; }\n  .badge { font-size:10px; padding:2px 6px; border-radius:99px; background:var(--line); color:var(--mut); }\n  .badge.stolen { background:rgba(239,68,68,.2); color:#fca5a5; }\n  .scroll { overflow-y:auto; }\n  .controls { display:flex; flex-wrap:wrap; gap:6px; }\n  button { font:inherit; cursor:pointer; border:1px solid var(--line); background:#243044; color:var(--txt);\n           padding:6px 10px; border-radius:7px; }\n  button:hover { border-color:var(--accent); }\n  button.alt { background:transparent; }\n  .alert { padding:8px 10px; border-left:3px solid var(--mut); background:#141c28; border-radius:0 6px 6px 0; margin-bottom:6px; }\n  .alert.geofence_exit { border-color:var(--red); }\n  .alert.movement { border-color:var(--amber); }\n  .alert.reappeared { border-color:var(--green); }\n  .alert .t { font-size:11px; text-transform:uppercase; letter-spacing:.05em; color:var(--mut); }\n  .alert .m { font-size:13px; margin-top:2px; }\n  .alert .dev { font-size:11px; color:var(--mut); margin-top:2px; }\n  .alerts-wrap { flex:1; }\n  .addtag { display:flex; flex-direction:column; gap:6px; }\n  .addtag input { font:inherit; background:#141c28; border:1px solid var(--line); color:var(--txt);\n                  padding:7px 9px; border-radius:7px; width:100%; }\n  .addtag input:focus, .addtag textarea:focus { outline:none; border-color:var(--accent); }\n  .addtag textarea { font:13px/1.4 ui-monospace,Menlo,monospace; background:#141c28;\n                     border:1px solid var(--line); color:var(--txt); padding:7px 9px; border-radius:7px; width:100%; resize:vertical; }\n  .asset .acts { display:flex; gap:6px; margin-top:6px; }\n  .asset .acts button { font-size:11px; padding:3px 8px; }\n  .asset .acts .del:hover { border-color:var(--red); color:#fca5a5; }\n  .fencerow { display:flex; gap:6px; }\n  .fencerow input { flex:1; }\n  #t_msg.ok { color:var(--green); } #t_msg.err { color:var(--red); }\n</style>\n</head>\n<body>\n  <div id=\"side\">\n    <header>\n      <h1>Localizit</h1>\n      <p>BLE + 4G tracker platform — webhook ingest + geofence &amp; movement alerts (prototype)</p>\n    </header>\n\n    <div class=\"section\">\n      <h2>Simulate pings <span id=\"simdev\" style=\"text-transform:none;color:var(--accent)\"></span></h2>\n      <div class=\"controls\">\n        <button onclick=\"sim('jitter')\" class=\"alt\">Jitter (no alert)</button>\n        <button onclick=\"sim('drift')\">Move 120m</button>\n        <button onclick=\"sim('escape')\">Leave geofence</button>\n        <button onclick=\"sim('silent')\">Reappear after silence</button>\n      </div>\n      <div class=\"controls\" style=\"margin-top:8px\">\n        <button onclick=\"toggleStolen()\" class=\"alt\" id=\"stolenBtn\">Toggle stolen mode</button>\n      </div>\n    </div>\n\n    <div class=\"section\">\n      <h2>Add a tag</h2>\n      <div class=\"addtag\">\n        <input id=\"t_id\" placeholder=\"Device ID (printed on the SpaceTag)\" />\n        <input id=\"t_name\" placeholder=\"Name — e.g. Makita drill\" />\n        <input id=\"t_site\" placeholder=\"Site / owner (optional)\" />\n        <div class=\"fencerow\">\n          <input id=\"t_radius\" type=\"number\" placeholder=\"Geofence radius (m, optional)\" />\n          <button onclick=\"useMapCentre()\" class=\"alt\" title=\"Use current map centre as the geofence centre\">Centre on map</button>\n        </div>\n        <div id=\"t_fencehint\" class=\"meta\" style=\"color:var(--mut)\"></div>\n        <button onclick=\"addTag()\">Add tag</button>\n        <div id=\"t_msg\" class=\"meta\"></div>\n      </div>\n      <details style=\"margin-top:10px\">\n        <summary style=\"cursor:pointer;color:var(--mut);font-size:12px\">Bulk import (CSV)</summary>\n        <div class=\"addtag\" style=\"margin-top:8px\">\n          <div class=\"meta\" style=\"color:var(--mut)\">One tag per line: <code>device_id, name, site, radius_m</code></div>\n          <textarea id=\"t_csv\" rows=\"4\" placeholder=\"SPACETAG-001, Makita drill, Greenfield, 250&#10;SPACETAG-002, DeWalt saw, Greenfield\"></textarea>\n          <button onclick=\"importCsv()\">Import tags</button>\n          <div id=\"t_imsg\" class=\"meta\"></div>\n        </div>\n      </details>\n    </div>\n\n    <div class=\"section scroll\" style=\"max-height:240px\">\n      <h2>Tracked assets</h2>\n      <div id=\"assets\"></div>\n    </div>\n\n    <div class=\"section scroll alerts-wrap\">\n      <h2>Live alerts</h2>\n      <div id=\"alerts\"></div>\n    </div>\n  </div>\n  <div id=\"map\"></div>\n\n<script src=\"https://unpkg.com/leaflet@1.9.4/dist/leaflet.js\"></script>\n<script>\nlet map, selected = null;\nconst layers = { markers:{}, track:null, fence:null };\n\nfunction init() {\n  map = L.map('map').setView([-36.8485, 174.7633], 14);\n  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',\n    { attribution:'© OpenStreetMap', maxZoom:19 }).addTo(map);\n  refresh();\n  setInterval(refresh, 3000);\n}\n\nasync function refresh() {\n  const assets = await (await fetch('/api/assets')).json();\n  if (!selected && assets.length) selected = assets[0].device_id;\n  renderAssets(assets);\n  renderMarkers(assets);\n  await renderTrackAndFence(assets);\n  renderAlerts(await (await fetch('/api/alerts')).json());\n  const sel = assets.find(a => a.device_id === selected);\n  document.getElementById('simdev').textContent = sel ? '— ' + sel.name : '';\n  document.getElementById('stolenBtn').textContent =\n    sel && sel.stolen_mode ? 'Stolen mode: ON' : 'Toggle stolen mode';\n}\n\nfunction renderAssets(assets) {\n  document.getElementById('assets').innerHTML = assets.map(a => `\n    <div class=\"asset ${a.device_id===selected?'active':''}\" onclick=\"select('${a.device_id}')\">\n      <div class=\"row\">\n        <span class=\"name\">${esc(a.name)}</span>\n        <span class=\"badge ${a.stolen_mode?'stolen':''}\">${a.stolen_mode?'STOLEN':'normal'}</span>\n      </div>\n      <div class=\"meta\">${esc(a.site||'—')} · ${a.last? 'last seen '+ago(a.last.received_at) : 'no reports yet'}</div>\n      <div class=\"acts\">\n        <button onclick=\"editTag(event,'${a.device_id}')\" class=\"alt\">Edit</button>\n        <button onclick=\"deleteTag(event,'${a.device_id}')\" class=\"alt del\">Delete</button>\n      </div>\n    </div>`).join('');\n}\n\nfunction renderMarkers(assets) {\n  for (const a of assets) {\n    if (!a.last) continue;\n    const ll = [a.last.latitude, a.last.longitude];\n    if (layers.markers[a.device_id]) layers.markers[a.device_id].setLatLng(ll);\n    else layers.markers[a.device_id] = L.marker(ll).addTo(map).bindPopup(esc(a.name));\n  }\n}\n\nasync function renderTrackAndFence(assets) {\n  const a = assets.find(x => x.device_id === selected);\n  if (!a) return;\n  if (layers.fence) { map.removeLayer(layers.fence); layers.fence = null; }\n  if (a.fence_lat != null) {\n    layers.fence = L.circle([a.fence_lat, a.fence_lng],\n      { radius:a.fence_radius_m, color:'#3b82f6', fillOpacity:.06 }).addTo(map);\n  }\n  const track = await (await fetch(`/api/assets/${a.device_id}/track`)).json();\n  if (layers.track) { map.removeLayer(layers.track); layers.track = null; }\n  if (track.length > 1) {\n    layers.track = L.polyline(track.map(t => [t.latitude, t.longitude]),\n      { color:'#f59e0b', weight:3, opacity:.7 }).addTo(map);\n  }\n}\n\nfunction renderAlerts(alerts) {\n  document.getElementById('alerts').innerHTML = alerts.length ? alerts.map(a => `\n    <div class=\"alert ${a.type}\">\n      <div class=\"t\">${a.type.replace('_',' ')}</div>\n      <div class=\"m\">${esc(a.message)}</div>\n      <div class=\"dev\">${esc(a.device_id)} · ${ago(a.created_at)}</div>\n    </div>`).join('') : '<div class=\"meta\" style=\"color:var(--mut)\">No alerts yet — try the simulator above.</div>';\n}\n\n// --- Add-tag form ---------------------------------------------------------\nlet pendingFence = null; // {lat,lng} chosen from map centre\nfunction useMapCentre(){\n  const c = map.getCenter();\n  pendingFence = { lat:+c.lat.toFixed(6), lng:+c.lng.toFixed(6) };\n  document.getElementById('t_fencehint').textContent =\n    `Geofence centre set to map view (${pendingFence.lat}, ${pendingFence.lng}). Pan the map to change.`;\n}\nasync function addTag(){\n  const msg = document.getElementById('t_msg');\n  const body = {\n    device_id: val('t_id'), name: val('t_name'), site: val('t_site'),\n  };\n  const radius = parseFloat(val('t_radius'));\n  if (Number.isFinite(radius) && pendingFence) {\n    body.fence_lat = pendingFence.lat; body.fence_lng = pendingFence.lng; body.fence_radius_m = radius;\n  }\n  const r = await fetch('/api/assets', { method:'POST',\n    headers:{'content-type':'application/json'}, body: JSON.stringify(body) });\n  const data = await r.json();\n  if (r.ok) {\n    msg.className = 'meta ok'; msg.textContent = `Added \"${data.name}\".`;\n    ['t_id','t_name','t_site','t_radius'].forEach(id => document.getElementById(id).value = '');\n    pendingFence = null; document.getElementById('t_fencehint').textContent = '';\n    selected = data.device_id; refresh();\n  } else {\n    msg.className = 'meta err'; msg.textContent = data.message || 'Could not add tag.';\n  }\n}\nfunction val(id){ return document.getElementById(id).value; }\n\nasync function importCsv(){\n  const msg = document.getElementById('t_imsg');\n  const csv = val('t_csv');\n  const r = await fetch('/api/assets/import', { method:'POST',\n    headers:{'content-type':'application/json'}, body: JSON.stringify({ csv }) });\n  const d = await r.json();\n  if (r.ok) {\n    msg.className = 'meta ok';\n    msg.textContent = `Imported ${d.added} tag(s)` + (d.skipped ? `, skipped ${d.skipped}.` : '.');\n    document.getElementById('t_csv').value = ''; refresh();\n  } else { msg.className = 'meta err'; msg.textContent = d.message || 'Import failed.'; }\n}\n\nasync function editTag(e, id){\n  e.stopPropagation();\n  const a = (await (await fetch('/api/assets')).json()).find(x => x.device_id === id);\n  if (!a) return;\n  const name = prompt('Tag name:', a.name); if (name === null) return;\n  const site = prompt('Site / owner:', a.site || ''); if (site === null) return;\n  await fetch('/api/assets/'+id, { method:'PUT', headers:{'content-type':'application/json'},\n    body: JSON.stringify({ name, site }) });\n  refresh();\n}\n\nasync function deleteTag(e, id){\n  e.stopPropagation();\n  if (!confirm('Delete this tag and all its location history & alerts?')) return;\n  await fetch('/api/assets/'+id, { method:'DELETE' });\n  if (selected === id) selected = null;\n  refresh();\n}\n\nfunction select(id){ selected = id; refresh(); }\nasync function sim(step){\n  await fetch('/api/simulate', { method:'POST', headers:{'content-type':'application/json'},\n    body: JSON.stringify({ deviceId: selected, step }) });\n  const a = (await (await fetch('/api/assets')).json()).find(x=>x.device_id===selected);\n  if (a && a.last) map.panTo([a.last.latitude, a.last.longitude]);\n  refresh();\n}\nasync function toggleStolen(){\n  const a = (await (await fetch('/api/assets')).json()).find(x=>x.device_id===selected);\n  if (!a) return;\n  await fetch('/api/assets/'+selected, { method:'PUT', headers:{'content-type':'application/json'},\n    body: JSON.stringify({ stolen_mode: a.stolen_mode ? 0 : 1 }) });\n  refresh();\n}\n\nfunction esc(s){ return String(s??'').replace(/[&<>\"]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;'}[c])); }\nfunction ago(t){\n  if(!t) return '—';\n  // Accept ISO (\"...Z\") or SQLite-style (\"YYYY-MM-DD HH:MM:SS\") timestamps.\n  let iso = String(t).replace(' ', 'T');\n  if(!/[zZ]|[+-]\\d\\d:?\\d\\d$/.test(iso)) iso += 'Z';\n  const s = Math.max(0,(Date.now()-Date.parse(iso))/1000);\n  if(Number.isNaN(s)) return '—';\n  if(s<60) return Math.round(s)+'s ago';\n  if(s<3600) return Math.round(s/60)+'m ago';\n  return Math.round(s/3600)+'h ago';\n}\ninit();\n</script>\n</body>\n</html>\n";
export const MONITOR_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n<title>Localizit — Factory Test Monitor</title>\n<link rel=\"stylesheet\" href=\"https://unpkg.com/leaflet@1.9.4/dist/leaflet.css\" />\n<style>\n  :root { --bg:#0f1419; --panel:#1a2230; --line:#2a3548; --txt:#e6edf3; --mut:#8b98a9; --green:#22c55e; --accent:#3b82f6; }\n  * { box-sizing:border-box; }\n  body { margin:0; font:15px/1.45 -apple-system,BlinkMacSystemFont,\"Segoe UI\",sans-serif; background:var(--bg); color:var(--txt); }\n  header { padding:16px 20px; border-bottom:1px solid var(--line); display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:8px; }\n  header h1 { margin:0; font-size:18px; }\n  header .sub { color:var(--mut); font-size:13px; margin-top:3px; }\n  .pill { font-size:12px; padding:4px 10px; border-radius:99px; background:#141c28; border:1px solid var(--line); color:var(--mut); }\n  .pill.live { color:var(--green); border-color:rgba(34,197,94,.4); }\n  .wrap { display:flex; gap:16px; padding:16px 20px; flex-wrap:wrap; }\n  #map { flex:1 1 420px; height:360px; border-radius:10px; overflow:hidden; min-width:300px; }\n  .panel { flex:1 1 420px; min-width:300px; }\n  table { width:100%; border-collapse:collapse; font-size:13px; }\n  th,td { text-align:left; padding:7px 8px; border-bottom:1px solid var(--line); }\n  th { color:var(--mut); font-weight:600; font-size:11px; text-transform:uppercase; letter-spacing:.05em; }\n  td.mono { font-family:ui-monospace,Menlo,monospace; font-size:12px; }\n  .empty { color:var(--mut); padding:20px 8px; }\n  .count { font-size:32px; font-weight:700; }\n</style>\n</head>\n<body>\n  <header>\n    <div>\n      <h1>Localizit — Factory Test Monitor</h1>\n      <div class=\"sub\">Read-only. Push test tags to the webhook and watch them appear here live.</div>\n    </div>\n    <div>\n      <span class=\"pill live\" id=\"status\">● live</span>\n      <span class=\"pill\" id=\"storage\"></span>\n    </div>\n  </header>\n  <div class=\"wrap\">\n    <div id=\"map\"></div>\n    <div class=\"panel\">\n      <div><span class=\"count\" id=\"count\">0</span> <span style=\"color:var(--mut)\">pings received</span> · <span class=\"sub\" id=\"updated\"></span></div>\n      <table>\n        <thead><tr><th>Device ID</th><th>Lat, Lng</th><th>Reported</th></tr></thead>\n        <tbody id=\"rows\"><tr><td colspan=\"3\" class=\"empty\">Waiting for the first ping…</td></tr></tbody>\n      </table>\n    </div>\n  </div>\n<script src=\"https://unpkg.com/leaflet@1.9.4/dist/leaflet.js\"></script>\n<script>\nconst token = decodeURIComponent(location.pathname.split('/monitor/')[1] || '');\nlet map, markers = {};\nfunction init(){\n  map = L.map('map').setView([0,0], 2);\n  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { attribution:'© OpenStreetMap', maxZoom:19 }).addTo(map);\n  tick(); setInterval(tick, 3000);\n}\nasync function tick(){\n  try {\n    const r = await fetch('/api/monitor/data?token=' + encodeURIComponent(token));\n    if (!r.ok) { document.getElementById('status').textContent = '● invalid token'; document.getElementById('status').className='pill'; return; }\n    const d = await r.json();\n    document.getElementById('storage').textContent = 'storage: ' + d.storage;\n    document.getElementById('count').textContent = d.count;\n    document.getElementById('updated').textContent = 'updated ' + new Date().toLocaleTimeString();\n    render(d.pings);\n  } catch(e) { /* keep trying */ }\n}\nfunction render(pings){\n  const tb = document.getElementById('rows');\n  if (!pings.length){ tb.innerHTML = '<tr><td colspan=\"3\" class=\"empty\">Waiting for the first ping…</td></tr>'; return; }\n  tb.innerHTML = pings.map(p => `<tr>\n      <td class=\"mono\">${esc(p.device_id)}${p.name? ' <span style=\"color:var(--mut)\">('+esc(p.name)+')</span>':''}</td>\n      <td class=\"mono\">${(+p.latitude).toFixed(5)}, ${(+p.longitude).toFixed(5)}</td>\n      <td>${ago(p.received_at)}</td></tr>`).join('');\n  const bounds = [];\n  for (const p of pings){\n    const ll = [+p.latitude, +p.longitude];\n    bounds.push(ll);\n    if (markers[p.device_id]) markers[p.device_id].setLatLng(ll);\n    else markers[p.device_id] = L.marker(ll).addTo(map).bindPopup(esc(p.device_id));\n  }\n  if (bounds.length) map.fitBounds(bounds, { maxZoom:15, padding:[40,40] });\n}\nfunction esc(s){ return String(s??'').replace(/[&<>\"]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;'}[c])); }\nfunction ago(t){\n  if(!t) return '—';\n  let iso = String(t).replace(' ','T'); if(!/[zZ]|[+-]\\d\\d:?\\d\\d$/.test(iso)) iso += 'Z';\n  const s = Math.max(0,(Date.now()-Date.parse(iso))/1000);\n  if(Number.isNaN(s)) return '—';\n  if(s<60) return Math.round(s)+'s ago';\n  if(s<3600) return Math.round(s/60)+'m ago';\n  return Math.round(s/3600)+'h ago';\n}\ninit();\n</script>\n</body>\n</html>\n";
